import React, { useState, useEffect } from "react";
import api from "../../api/axios";
import toast from "react-hot-toast";
import "./Admin.css";
import "./Quizzes.css";

const INIT_QUIZ = {
  lessonId: "",
  title: "",
  examType: "IELTS",
  examPart: "",
  instructions: "",
  timeLimit: 60,
  passageText: "",
  audioUrl: ""
};

export default function AdminQuizzes() {
  const [quizzes, setQuizzes] = useState([]);
  const [lessons, setLessons] = useState([]);
  const [loading, setLoading] = useState(true);

  const [creating, setCreating] = useState(false);
  const [quizForm, setQuizForm] = useState(INIT_QUIZ);

  const [filterType, setFilterType] = useState("");
  const [viewModal, setViewModal] = useState(null);
  const [editModal, setEditModal] = useState(null);

  // ================= FETCH =================
  const fetchData = async () => {
    setLoading(true);
    try {
      const [qRes, lRes] = await Promise.all([
        api.get("/quizzes"),
        api.get("/lessons").catch(() => ({ data: { data: [] } }))
      ]);

      setQuizzes(qRes.data.data || []);
      setLessons(lRes.data.data || []);
    } catch (e) {
      console.error(e);
      toast.error("Không thể tải dữ liệu");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const filtered = quizzes.filter(
    q => !filterType || q.examType === filterType
  );

  // ================= ACTIONS =================
  const handleDelete = async id => {
    if (!window.confirm("Xóa bài kiểm tra?")) return;
    try {
      await api.delete(`/quizzes/${id}`);
      toast.success("Đã xóa");
      fetchData();
    } catch {
      toast.error("Không thể xóa");
    }
  };

  const handleUpdate = async () => {
    try {
      await api.put(`/quizzes/${editModal.id}`, editModal);
      toast.success("Cập nhật thành công");
      setEditModal(null);
      fetchData();
    } catch {
      toast.error("Cập nhật thất bại");
    }
  };

  // ================= UI =================
  return (
    <div className="admin-page fade-in">

      {/* ================= HEADER ================= */}
      <div className="page-header">
        <h1>Bài kiểm tra</h1>
        <p>Quản lý bài kiểm tra IELTS và TOEIC</p>
      </div>

      {/* ================= TOOLBAR ================= */}
      <div className="toolbar">
        <div className="toolbar-left">
          <select
            className="filter-select"
            value={filterType}
            onChange={e => setFilterType(e.target.value)}
          >
            <option value="">Tất cả</option>
            <option value="IELTS">IELTS</option>
            <option value="TOEIC">TOEIC</option>
          </select>
        </div>

        <button
          className="btn btn-primary"
          onClick={() => setCreating(true)}
        >
          + Tạo bài kiểm tra
        </button>
      </div>

      {/* ================= CONTENT ================= */}
      {creating ? (
        <div className="section-card">
          <h3>Tạo bài kiểm tra</h3>

          <div className="form-group">
            <label>Tiêu đề</label>
            <input
              value={quizForm.title}
              onChange={e =>
                setQuizForm({ ...quizForm, title: e.target.value })
              }
            />
          </div>

          <div className="form-row">
            <div className="form-group">
              <label>Loại</label>
              <select
                value={quizForm.examType}
                onChange={e =>
                  setQuizForm({ ...quizForm, examType: e.target.value })
                }
              >
                <option value="IELTS">IELTS</option>
                <option value="TOEIC">TOEIC</option>
              </select>
            </div>

            <div className="form-group">
              <label>Thời gian</label>
              <input
                type="number"
                value={quizForm.timeLimit}
                onChange={e =>
                  setQuizForm({
                    ...quizForm,
                    timeLimit: Number(e.target.value)
                  })
                }
              />
            </div>
          </div>

          <div style={{ display: "flex", gap: 8 }}>
            <button
              className="btn btn-ghost"
              onClick={() => setCreating(false)}
            >
              Hủy
            </button>

            <button
              className="btn btn-primary"
              onClick={async () => {
                try {
                  await api.post("/quizzes", quizForm);
                  toast.success("Tạo thành công");
                  setCreating(false);
                  setQuizForm(INIT_QUIZ);
                  fetchData();
                } catch {
                  toast.error("Thất bại");
                }
              }}
            >
              Lưu
            </button>
          </div>
        </div>
      ) : (
        <div className="table-wrapper">
          {loading ? (
            <div className="page-loading">
              <div className="spinner" />
            </div>
          ) : (
            <table className="data-table">
              <thead>
                <tr>
                  <th>Tiêu đề</th>
                  <th>Loại</th>
                  <th>Phần</th>
                  <th>Thời gian</th>
                  <th>Thao tác</th>
                </tr>
              </thead>

              <tbody>
                {filtered.length === 0 ? (
                  <tr>
                    <td colSpan={5}>Chưa có dữ liệu</td>
                  </tr>
                ) : (
                  filtered.map(q => (
                    <tr key={q.id}>
                      <td>{q.title}</td>
                      <td>{q.examType}</td>
                      <td>{q.examPart || "-"}</td>
                      <td>{q.timeLimit} phút</td>

                      <td style={{ display: "flex", gap: 4 }}>
                        <button
                          className="btn btn-info btn-sm"
                          onClick={() => setViewModal(q)}
                        >
                          👁️
                        </button>

                        <button
                          className="btn btn-warning btn-sm"
                          onClick={() => setEditModal({ ...q })}
                        >
                          ✏️
                        </button>

                        <button
                          className="btn btn-danger btn-sm"
                          onClick={() => handleDelete(q.id)}
                        >
                          🗑️
                        </button>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          )}
        </div>
      )}

      {/* ================= VIEW MODAL ================= */}
      {viewModal && (
        <div
          className="modal-overlay"
          onClick={() => setViewModal(null)}
        >
          <div
            className="modal"
            onClick={e => e.stopPropagation()}
          >
            <h3>{viewModal.title}</h3>
            <p>Loại: {viewModal.examType}</p>
            <p>Thời gian: {viewModal.timeLimit} phút</p>

            <button onClick={() => setViewModal(null)}>
              Đóng
            </button>
          </div>
        </div>
      )}

      {/* ================= EDIT MODAL ================= */}
      {editModal && (
        <div
          className="modal-overlay"
          onClick={() => setEditModal(null)}
        >
          <div
            className="modal"
            onClick={e => e.stopPropagation()}
          >
            <h3>Sửa bài kiểm tra</h3>

            <input
              value={editModal.title}
              onChange={e =>
                setEditModal({
                  ...editModal,
                  title: e.target.value
                })
              }
            />

            <button onClick={handleUpdate}>
              Lưu
            </button>
          </div>
        </div>
      )}
    </div>
  );
}
